  // ════════ BUDGET : sous-onglet principal (Recettes / Dépenses / Résultat net) ════════
  // "Recettes" = ancien module Paiements (inchangé). "Dépenses" et "Résultat net" = nouveaux.
  type BudgetTab = "recettes" | "depenses" | "resultat";
